 34→func TestValidateRequest(t *testing.T) {
 35→	t.Parallel()
 36→	reg := search.NewRegistry()
 37→
 38→	t.Run("unknown field", func(t *testing.T) {
 39→		req := search.SearchRequest{
 40→			Filters: []search.FilterInput{
 41→				{Field: "does_not_exist", Value: mustJSON(map[string]any{"value": "x"})},
 42→			},
 43→		}
 44→		errs := search.ValidateRequest(reg, req, true)
 45→		if len(errs) != 1 {
 46→			t.Fatalf("expected 1 error, got %d", len(errs))
 47→		}
 48→		if errs[0].Field != "does_not_exist" {
 49→			t.Errorf("expected field 'does_not_exist', got %q", errs[0].Field)
 50→		}
 51→		if errs[0].Message != "unknown field" {
 52→			t.Errorf("unexpected message: %q", errs[0].Message)
 53→		}
 54→	})
 55→
 56→	t.Run("bad enum value for state", func(t *testing.T) {
 57→		req := search.SearchRequest{
 58→			Filters: []search.FilterInput{
 59→				{Field: "state", Value: mustJSON(search.MultiEnumFilter{Values: []string{"XX"}})},
 60→			},
 61→		}
 62→		errs := search.ValidateRequest(reg, req, true)
 63→		if len(errs) != 1 {
 64→			t.Fatalf("expected 1 error, got %d", len(errs))
 65→		}
 66→		if !strings.Contains(errs[0].Message, "not in allowed options") {
 67→			t.Errorf("unexpected message: %q", errs[0].Message)
 68→		}
 69→	})
 70→
 71→	t.Run("multi enum bad value", func(t *testing.T) {
 72→		req := search.SearchRequest{
 73→			Filters: []search.FilterInput{
 74→				{Field: "application_platforms", Value: mustJSON(search.MultiEnumFilter{Values: []string{"Not A Real App"}})},
 75→			},
 76→		}
 77→		errs := search.ValidateRequest(reg, req, true)
 78→		if len(errs) != 1 {
 79→			t.Fatalf("expected 1 error, got %d: %v", len(errs), errs)
 80→		}
 81→		if !strings.Contains(errs[0].Message, "not in allowed options") {
 82→			t.Errorf("unexpected message: %q", errs[0].Message)
 83→		}
 84→	})
 85→
 86→	t.Run("multi enum empty values", func(t *testing.T) {
 87→		req := search.SearchRequest{
 88→			Filters: []search.FilterInput{
 89→				{Field: "application_platforms", Value: mustJSON(search.MultiEnumFilter{Values: []string{}})},
 90→			},
 91→		}
 92→		errs := search.ValidateRequest(reg, req, true)
 93→		if len(errs) != 1 {
 94→			t.Fatalf("expected 1 error, got %d", len(errs))
 95→		}
 96→		if errs[0].Message != "at least one value required" {
 97→			t.Errorf("unexpected message: %q", errs[0].Message)
 98→		}
 99→	})
