  9→func TestMultiEnumField_ArrayAll(t *testing.T) {
 10→	t.Parallel()
 11→	f := &MultiEnumField{
 12→		baseField: baseField{
 13→			name:   "test_array_all",
 14→			source: FieldSource{Kind: SourceJSONBPath, JSONBPath: []string{"test_key"}, ValueType: JSONBArray},
 15→		},
 16→		SelectionMode: SelectionModeAll,
 17→		StorageFormat: JSONBStorageFormatArray,
 18→	}
 19→	raw, _ := json.Marshal(MultiEnumFilter{Values: []string{"a", "b"}})
 20→	expr, _, err := f.BuildSQL(raw, 1)
 21→	if err != nil {
 22→		t.Fatal(err)
 23→	}
 24→	if !strings.Contains(expr, "@>") {
 25→		t.Errorf("expected @> operator: %s", expr)
 26→	}
 27→	if !strings.Contains(expr, "::jsonb") {
 28→		t.Errorf("expected ::jsonb cast: %s", expr)
 29→	}
 30→}
