 72→func TestSqlCastType_AllBranches(t *testing.T) {
 73→	t.Parallel()
 74→	cases := []struct {
 75→		vt   JSONBValueType
 76→		want string
 77→	}{
 78→		{JSONBInteger, "integer"},
 79→		{JSONBNumeric, "numeric"},
 80→		{JSONBBoolean, "boolean"},
 81→		{JSONBText, "text"},
 82→		{JSONBArray, "text"},   // default
 83→		{JSONBObject, "text"},  // default
 84→	}
 85→	for _, tc := range cases {
