	t.Parallel()
	reg := search.NewRegistry()

	t.Run("no filters", func(t *testing.T) {
		req := search.SearchRequest{Limit: 20, Offset: 0}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "FROM search_base.dataset_merged") {
			t.Errorf("missing table: %s", sql)
		}
		if strings.Contains(sql, "WHERE") {
			t.Errorf("unexpected WHERE clause for no filters: %s", sql)
		}
		if !strings.Contains(sql, "LIMIT") || !strings.Contains(sql, "OFFSET") {
			t.Errorf("missing pagination: %s", sql)
		}
		// Two pagination args: limit + offset
		if len(args) != 2 {
			t.Errorf("expected 2 args (limit/offset), got %d", len(args))
		}
	})

