		}
		return f
	}

	fieldNames := []string{
		"name", "ncaa_conference", "unit_id", "carnegie_basic", "enrollment",
		"institution_type", "state", "application_platforms",
		"location", "rank_us_news_national", "fields_of_study",
	}
	for _, name := range fieldNames {
		t.Run(name+"_invalid_json", func(t *testing.T) {
			f := lookup(name)
			_, _, err := f.BuildSQL(bad, 1)
			if err == nil {
				t.Error("expected error for invalid JSON")
			}
		})
	}
}

