func TestBuildQuery(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("no filters", func(t *testing.T) {
		req := search.SearchRequest{Limit: 20, Offset: 0}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "FROM search_base.dataset_merged") {
			t.Errorf("missing table: %s", sql)
		}
		// Permanent degree filter is always present.
		if !strings.Contains(sql, "WHERE") {
			t.Errorf("expected WHERE clause with permanent filter: %s", sql)
		}
		if !strings.Contains(sql, "degrees_awarded_highest") {
			t.Errorf("expected permanent degree filter: %s", sql)
		}
		if !strings.Contains(sql, "LIMIT") || !strings.Contains(sql, "OFFSET") {
			t.Errorf("missing pagination: %s", sql)
		}
		// Two pagination args: limit + offset (permanent filter has no args)
		if len(args) != 2 {
			t.Errorf("expected 2 args (limit/offset), got %d", len(args))
		}
	})

	t.Run("single numeric range filter", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "enrollment", Value: mustJSON(search.NumericRangeFilter{Min: ptrF(1000), Max: ptrF(50000)})},
			},
			Limit: 10,
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "WHERE") {
			t.Errorf("expected WHERE clause: %s", sql)
		}
		if !strings.Contains(sql, "BETWEEN") {
			t.Errorf("expected BETWEEN in SQL: %s", sql)
		}
		// 2 filter args + 2 pagination args
		if len(args) != 4 {
			t.Errorf("expected 4 args, got %d: %v", len(args), args)
		}
	})

	t.Run("geo radius filter", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "location", Value: mustJSON(search.GeoFilterInput{
					Kind:   search.GeoFilterKindRadius,
					Radius: &search.GeoRadiusFilter{Lat: 40.7, Lng: -74.0, RadiusKm: 50},
				})},
			},
			Limit: 20,
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ST_DWithin") {
			t.Errorf("expected ST_DWithin: %s", sql)
		}
		// 3 geo args + 2 pagination = 5
		if len(args) != 5 {
			t.Errorf("expected 5 args, got %d", len(args))
		}
	})

	t.Run("multi enum any filter", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "application_platforms", Value: mustJSON(search.MultiEnumFilter{Values: []string{"Common", "Coalition"}})},
			},
			Limit: 20,
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "?|") {
			t.Errorf("expected ?| operator: %s", sql)
		}
		// 1 multi-enum arg + 2 pagination = 3
		if len(args) != 3 {
			t.Errorf("expected 3 args, got %d", len(args))
		}
	})

	t.Run("ranking field", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "rank_us_news_national", Value: mustJSON(search.NumericRangeFilter{Min: ptrF(1), Max: ptrF(50)})},
			},
			Limit: 20,
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "'rank'") {
			t.Errorf("expected method guard: %s", sql)
		}
		if !strings.Contains(sql, "BETWEEN") {
			t.Errorf("expected BETWEEN: %s", sql)
		}
		// 2 rank args + 2 pagination = 4
		if len(args) != 4 {
			t.Errorf("expected 4 args, got %d", len(args))
		}
	})

	t.Run("count query has no limit offset", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "state", Value: mustJSON(search.MultiEnumFilter{Values: []string{"VT"}})},
			},
		}
		sql, args, err := search.BuildCountQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.HasPrefix(sql, "SELECT COUNT(*)") {
			t.Errorf("expected COUNT(*): %s", sql)
		}
		if strings.Contains(sql, "LIMIT") {
			t.Errorf("unexpected LIMIT in count query: %s", sql)
		}
		if len(args) != 1 {
			t.Errorf("expected 1 arg, got %d", len(args))
		}
	})

	t.Run("multiple filters join with AND", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "state", Value: mustJSON(search.MultiEnumFilter{Values: []string{"CA"}})},
				{Field: "enrollment", Value: mustJSON(search.NumericRangeFilter{Min: ptrF(5000)})},
			},
			Limit: 20,
		}
		sql, _, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, " AND ") {
			t.Errorf("expected AND between clauses: %s", sql)
		}
	})
}

// ─────────────────────────────────────────────────────────────────────────────
// Table-driven BuildSQL test for every registry field
// ─────────────────────────────────────────────────────────────────────────────

func TestBuildSQLAllFields(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	for _, f := range reg.All() {
		f := f // capture
		t.Run(f.Name(), func(t *testing.T) {
			raw := minimalFilter(f)
			if raw == nil {
				t.Skipf("no minimal filter for kind %s", f.Kind())
			}

			expr, args, err := f.BuildSQL(raw, 1)
			if err != nil {
				t.Fatalf("BuildSQL error: %v", err)
			}
			if strings.TrimSpace(expr) == "" {
				t.Fatalf("BuildSQL returned empty expression")
			}

			// Verify placeholder count matches arg count.
			np := countPlaceholders(expr)
			if np != len(args) {
				t.Errorf("placeholder count %d != arg count %d\nexpr: %s\nargs: %v",
					np, len(args), expr, args)
			}

			// Verify no obvious SQL injection via string interpolation:
			// all variable data must appear only as $N placeholders.
			if strings.Contains(expr, "test_injection") {
				t.Errorf("value leaked into SQL expression: %s", expr)
			}
		})
	}
}

// minimalFilter returns a minimal valid JSON filter for the given field.
func minimalFilter(f search.Field) json.RawMessage {
	desc := f.Descriptor()
	switch f.Kind() {
	case search.KindFullText:
		return mustJSON(search.FullTextFilter{Query: "test_query"})
	case search.KindSubstring:
		return mustJSON(search.SubstringFilter{Value: "test_value"})
	case search.KindExactString:
		return mustJSON(search.ExactStringFilter{Value: "test_value"})
	case search.KindExactNumeric:
		return mustJSON(search.ExactNumericFilter{Value: 1})
	case search.KindNumericRange:
		return mustJSON(search.NumericRangeFilter{Min: ptrF(1)})
	case search.KindSingleEnum:
		if len(desc.Options) > 0 {
			return mustJSON(search.SingleEnumFilter{Value: desc.Options[0].Value})
		}
		return mustJSON(search.SingleEnumFilter{Value: "test"})
	case search.KindMultiEnum:
		if len(desc.Options) > 0 {
			return mustJSON(search.MultiEnumFilter{Values: []string{desc.Options[0].Value}})
		}
		return mustJSON(search.MultiEnumFilter{Values: []string{"52.0101"}})
	case search.KindGeo:
		return mustJSON(search.GeoFilterInput{
			Kind:   search.GeoFilterKindRadius,
			Radius: &search.GeoRadiusFilter{Lat: 40.7, Lng: -74.0, RadiusKm: 50},
		})
	}
	return nil
}

