func TestBuildSQLShapes(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	lookup := func(name string) search.Field {
		f, ok := reg.Lookup(name)
		if !ok {
			t.Fatalf("field %q not found in registry", name)
		}
		return f
	}

	t.Run("full_text uses plainto_tsquery", func(t *testing.T) {
		f := lookup("name")
		expr, args, err := f.BuildSQL(mustJSON(search.FullTextFilter{Query: "MIT"}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "plainto_tsquery") {
			t.Errorf("expected plainto_tsquery: %s", expr)
		}
		if len(args) != 1 || args[0] != "MIT" {
			t.Errorf("unexpected args: %v", args)
		}
	})

	t.Run("substring uses ILIKE with concat", func(t *testing.T) {
		f := lookup("ncaa_conference")
		expr, args, err := f.BuildSQL(mustJSON(search.SubstringFilter{Value: "big ten"}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "ILIKE") {
			t.Errorf("expected ILIKE: %s", expr)
		}
		if len(args) != 1 || args[0] != "big ten" {
			t.Errorf("unexpected args: %v", args)
		}
	})

	t.Run("ncaa_conference JSONB substring has null guard", func(t *testing.T) {
		f := lookup("ncaa_conference")
		expr, _, err := f.BuildSQL(mustJSON(search.SubstringFilter{Value: "ACC"}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "IS NOT NULL") {
			t.Errorf("expected IS NOT NULL guard for JSONB source: %s", expr)
		}
	})

	t.Run("enrollment JSONB range has null guard", func(t *testing.T) {
		f := lookup("enrollment")
		expr, _, err := f.BuildSQL(mustJSON(search.NumericRangeFilter{Min: ptrF(1000)}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "IS NOT NULL") {
			t.Errorf("expected IS NOT NULL guard: %s", expr)
		}
		if !strings.Contains(expr, "::integer") {
			t.Errorf("expected ::integer cast: %s", expr)
		}
	})

	t.Run("ranking field has method guard", func(t *testing.T) {
		f := lookup("rank_us_news_national")
		expr, args, err := f.BuildSQL(mustJSON(search.NumericRangeFilter{Min: ptrF(1), Max: ptrF(100)}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "method") || !strings.Contains(expr, "'rank'") {
			t.Errorf("expected method guard: %s", expr)
		}
		if len(args) != 2 {
			t.Errorf("expected 2 args, got %d", len(args))
		}
	})

	t.Run("geo bbox uses ST_Intersects", func(t *testing.T) {
		f := lookup("location")
		expr, args, err := f.BuildSQL(mustJSON(search.GeoFilterInput{
			Kind: search.GeoFilterKindBBox,
			BBox: &search.GeoBoundingBoxFilter{MinLat: 40, MaxLat: 42, MinLng: -75, MaxLng: -72},
		}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "ST_Intersects") {
			t.Errorf("expected ST_Intersects: %s", expr)
		}
		if len(args) != 4 {
			t.Errorf("expected 4 args, got %d", len(args))
		}
	})

	t.Run("state multi-select uses ANY", func(t *testing.T) {
		f := lookup("state")
		expr, args, err := f.BuildSQL(mustJSON(search.MultiEnumFilter{Values: []string{"CA", "NY", "TX"}}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "= ANY($1::text[])") {
			t.Errorf("expected ANY operator: %s", expr)
		}
		// 1 array arg
		if len(args) != 1 {
			t.Errorf("expected 1 arg, got %d", len(args))
		}
		// verify the arg is the slice
		vals, ok := args[0].([]string)
		if !ok {
			t.Fatalf("expected []string arg, got %T", args[0])
		}
		if len(vals) != 3 {
			t.Errorf("expected 3 values in arg, got %d", len(vals))
		}
	})

	t.Run("state multi-select argStart increments correctly", func(t *testing.T) {
		f := lookup("state")
		expr, _, err := f.BuildSQL(mustJSON(search.MultiEnumFilter{Values: []string{"CA"}}), 5)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "$5") {
			t.Errorf("expected $5 placeholder at argStart=5: %s", expr)
		}
	})

	t.Run("state multi-select empty values error", func(t *testing.T) {
		f := lookup("state")
		_, _, err := f.BuildSQL(mustJSON(search.MultiEnumFilter{Values: []string{}}), 1)
		if err == nil {
			t.Fatal("expected error for empty values")
		}
		if err.Error() != "at least one value required" {
			t.Errorf("unexpected error: %v", err)
		}
	})

	t.Run("state multi-select invalid JSON error", func(t *testing.T) {
		f := lookup("state")
		_, _, err := f.BuildSQL(json.RawMessage(`not-json`), 1)
		if err == nil {
			t.Fatal("expected JSON parse error")
		}
	})

	t.Run("multi enum object_key all uses ?&", func(t *testing.T) {
		// fields_of_study is object_key/any — we build a multi-all field manually
		// to test the ?& path without adding it to the registry.
		// (Registry only uses SelectionModeAny for these fields.)
		// Verify the any path (?|) for fields_of_study.
		f := lookup("fields_of_study")
		expr, _, err := f.BuildSQL(mustJSON(search.MultiEnumFilter{Values: []string{"52.0101"}}), 1)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(expr, "?|") {
			t.Errorf("expected ?| for object_key/any: %s", expr)
		}
	})

	t.Run("placeholder index advances correctly across multiple filters", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "enrollment", Value: mustJSON(search.NumericRangeFilter{Min: ptrF(100), Max: ptrF(5000)})},
				{Field: "state", Value: mustJSON(search.MultiEnumFilter{Values: []string{"NY"}})},
			},
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		// enrollment: 2 args ($1,$2), state: 1 arg ($3), limit: $4, offset: $5
		if len(args) != 5 {
			t.Errorf("expected 5 args, got %d: %v", len(args), args)
		}
		// Check $3 comes after $2 in the SQL (state clause uses $3)
		idx2 := strings.Index(sql, "$2")
		idx3 := strings.Index(sql, "$3")
		if idx2 < 0 || idx3 < 0 || idx3 < idx2 {
			t.Errorf("placeholder ordering wrong: %s", sql)
		}
	})
}

