func TestPermanentDegreeFilter_PresentInAllQueryTypes(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("BuildQuery without user filters", func(t *testing.T) {
		sql, args, err := search.BuildQuery(reg, search.SearchRequest{Limit: 10})
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "degrees_awarded_highest") {
			t.Errorf("permanent filter missing from BuildQuery: %s", sql)
		}
		// Only pagination args; permanent filter uses no placeholders.
		if len(args) != 2 {
			t.Errorf("expected 2 args (limit/offset), got %d", len(args))
		}
	})

	t.Run("BuildQuery with user filter preserves placeholder numbering", func(t *testing.T) {
		req := search.SearchRequest{
			Filters: []search.FilterInput{
				{Field: "enrollment", Value: mustJSON(search.NumericRangeFilter{Min: ptrF(1000), Max: ptrF(50000)})},
			},
			Limit: 10,
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "degrees_awarded_highest") {
			t.Errorf("permanent filter missing: %s", sql)
		}
		// Filter args ($1, $2) + pagination args ($3, $4) = 4
		if len(args) != 4 {
			t.Errorf("expected 4 args, got %d", len(args))
		}
		// First filter placeholder should be $1.
		if !strings.Contains(sql, "$1") {
			t.Errorf("expected $1 placeholder for user filter: %s", sql)
		}
	})

	t.Run("BuildCountQuery without user filters", func(t *testing.T) {
		sql, _, err := search.BuildCountQuery(reg, search.SearchRequest{})
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "degrees_awarded_highest") {
			t.Errorf("permanent filter missing from BuildCountQuery: %s", sql)
		}
	})

	t.Run("BuildExportQuery without user filters", func(t *testing.T) {
		sql, _, err := search.BuildExportQuery(reg, search.SearchRequest{Limit: 10}, 500)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "degrees_awarded_highest") {
			t.Errorf("permanent filter missing from BuildExportQuery: %s", sql)
		}
	})
}

