func TestBuildQuery_WithUserLocation(t *testing.T) {
	t.Parallel()
	reg := search.NewRegistry()

	t.Run("distance column computed", func(t *testing.T) {
		req := search.SearchRequest{
			Limit:        10,
			UserLocation: &search.UserLocation{Latitude: 42.0, Longitude: -72.0},
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ST_Distance") {
			t.Errorf("expected ST_Distance in SQL: %s", sql)
		}
		if !strings.Contains(sql, "1609.344") {
			t.Errorf("expected meters-to-miles conversion: %s", sql)
		}
		// NULL::integer for myPrice (no state provided)
		if !strings.Contains(sql, "NULL::integer") {
			t.Errorf("expected NULL::integer for myPrice when no state: %s", sql)
		}
		// 2 geo args + 2 pagination = 4
		if len(args) != 4 {
			t.Errorf("expected 4 args, got %d: %v", len(args), args)
		}
		// First two args: longitude, latitude
		if args[0] != -72.0 {
			t.Errorf("args[0] (lng) = %v, want -72.0", args[0])
		}
		if args[1] != 42.0 {
			t.Errorf("args[1] (lat) = %v, want 42.0", args[1])
		}
	})

	t.Run("distance and myPrice with state", func(t *testing.T) {
		req := search.SearchRequest{
			Limit:        10,
			UserLocation: &search.UserLocation{Latitude: 42.0, Longitude: -72.0, State: "MA"},
		}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "ST_Distance") {
			t.Errorf("expected ST_Distance: %s", sql)
		}
		if !strings.Contains(sql, "tuition_in_state") {
			t.Errorf("expected tuition_in_state in myPrice CASE: %s", sql)
		}
		if !strings.Contains(sql, "tuition_out_of_state") {
			t.Errorf("expected tuition_out_of_state in myPrice CASE: %s", sql)
		}
		// 2 geo args + 1 state arg + 2 pagination = 5
		if len(args) != 5 {
			t.Errorf("expected 5 args, got %d: %v", len(args), args)
		}
		if args[2] != "MA" {
			t.Errorf("args[2] (state) = %v, want MA", args[2])
		}
	})

	t.Run("no user location produces NULL columns", func(t *testing.T) {
		req := search.SearchRequest{Limit: 10}
		sql, args, err := search.BuildQuery(reg, req)
		if err != nil {
			t.Fatal(err)
		}
		if !strings.Contains(sql, "NULL::double precision") {
			t.Errorf("expected NULL::double precision: %s", sql)
		}
		if !strings.Contains(sql, "NULL::integer") {
			t.Errorf("expected NULL::integer: %s", sql)
		}
		// Only 2 pagination args
		if len(args) != 2 {
			t.Errorf("expected 2 args, got %d", len(args))
		}
	})
}

